import { useState, useEffect, useRef } from "react";

// ============================================================
// STORAGE
// ============================================================
const load = (key, def) => { try { const v = localStorage.getItem(key); return v ? JSON.parse(v) : def; } catch { return def; } };
const save = (key, val) => { try { localStorage.setItem(key, JSON.stringify(val)); } catch {} };

// ============================================================
// INITIAL DATA
// ============================================================
const ENGINEERS = ["أحمد هارون", "محمد النجار", "محمد موسى", "خالد إبراهيم", "عمر سعيد"];

const INIT_SITES = Array.from({ length: 44 }, (_, i) => ({
  id: `site-${i+1}`,
  name: `فيلا ${100 + i + 1}`,
  plot: `9141${2000 + i}`,
  engineer: ENGINEERS[i % ENGINEERS.length],
  progress: [26,45,60,72,35,18,90,55,40,80,22,65,48,33,77,12,58,42,88,30,50,68,15,95,37,62,25,73,44,85,19,56,38,70,28,82,47,20,64,91,34,59,76,43][i],
  status: i > 41 ? "مكتمل" : i % 5 === 0 ? "متوقف" : "جارٍ التنفيذ",
  createdAt: new Date().toISOString(),
}));

const INIT_REQUESTS = [
  { id:"MR-001", siteId:"site-1", site:"فيلا 101", material:"حديد تسليح Ø16", qty:5, unit:"طن", requestedBy:"أحمد هارون", date:"2026-06-10", phase:"توريد", notes:"", rejectedReason:"" },
  { id:"MR-002", siteId:"site-15", site:"فيلا 115", material:"خشب كونتر 18مم", qty:120, unit:"م²", requestedBy:"محمد النجار", date:"2026-06-15", phase:"أمر شراء", notes:"", rejectedReason:"" },
  { id:"MR-003", siteId:"site-3", site:"فيلا 103", material:"رمل ناعم", qty:10, unit:"م³", requestedBy:"محمد النجار", date:"2026-06-21", phase:"طلب", notes:"", rejectedReason:"" },
];

const TODAY = new Date().toISOString().split("T")[0];

const PHASES = ["طلب","عرض سعر","اعتماد","أمر شراء","توريد","صرف"];
const PHASE_NEXT = {"طلب":"عرض سعر","عرض سعر":"اعتماد","اعتماد":"أمر شراء","أمر شراء":"توريد","توريد":"صرف"};
const PHASE_COLOR = {"طلب":"#6B7280","عرض سعر":"#F59E0B","اعتماد":"#3B82F6","أمر شراء":"#8B5CF6","توريد":"#10B981","صرف":"#059669"};
const STATUS_COLOR = {"جارٍ التنفيذ":"#10B981","متوقف":"#EF4444","مكتمل":"#6B7280"};
const ROLE_COLOR = {"مدير":"#10B981","مهندس":"#3B82F6","مشتريات":"#F59E0B"};
const TYPE_ICON = {"رسالة":"✉️","تقرير تقدم":"📊","أمر تغيير":"🔄","رسم هندسي":"📐","أخرى":"📄"};

// ============================================================
// SHARED UI
// ============================================================
const PhaseBar = ({ current }) => {
  const idx = PHASES.indexOf(current);
  return (
    <div style={{display:"flex",borderRadius:8,overflow:"hidden",fontSize:9}}>
      {PHASES.map((p,i)=>(
        <div key={p} style={{flex:1,padding:"4px 1px",textAlign:"center",
          background:i<idx?"#1B2A4A":i===idx?"#B8923C":"#E5E7EB",
          color:i<=idx?"#fff":"#9CA3AF",fontWeight:i===idx?800:400,
          borderRight:i<PHASES.length-1?"1px solid #fff":"none"}}>{p}</div>
      ))}
    </div>
  );
};

const Badge = ({label,color}) => (
  <span style={{background:color+"20",color,border:`1px solid ${color}40`,borderRadius:20,padding:"2px 10px",fontSize:11,fontWeight:600,whiteSpace:"nowrap"}}>{label}</span>
);

const Card = ({children,style={},onClick}) => (
  <div onClick={onClick} style={{background:"#fff",borderRadius:12,padding:16,boxShadow:"0 1px 4px rgba(0,0,0,0.08)",marginBottom:12,cursor:onClick?"pointer":"default",...style}}>{children}</div>
);

const Input = ({label,value,onChange,placeholder,type="text",required,rows}) => (
  <div style={{marginBottom:14}}>
    {label && <div style={{fontSize:13,fontWeight:600,color:"#374151",marginBottom:5}}>{label}{required&&<span style={{color:"#EF4444"}}> *</span>}</div>}
    {rows ? (
      <textarea rows={rows} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
        style={{width:"100%",padding:"10px 12px",border:"1px solid #D1D5DB",borderRadius:8,fontSize:13,direction:"rtl",fontFamily:"inherit",boxSizing:"border-box",background:"#F9FAFB",resize:"vertical"}} />
    ) : (
      <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
        style={{width:"100%",padding:"10px 12px",border:"1px solid #D1D5DB",borderRadius:8,fontSize:13,direction:"rtl",fontFamily:"inherit",boxSizing:"border-box",background:"#F9FAFB"}} />
    )}
  </div>
);

const Select = ({label,value,onChange,options,required}) => (
  <div style={{marginBottom:14}}>
    {label && <div style={{fontSize:13,fontWeight:600,color:"#374151",marginBottom:5}}>{label}{required&&<span style={{color:"#EF4444"}}> *</span>}</div>}
    <select value={value} onChange={e=>onChange(e.target.value)}
      style={{width:"100%",padding:"10px 12px",border:"1px solid #D1D5DB",borderRadius:8,fontSize:13,direction:"rtl",fontFamily:"inherit",background:"#F9FAFB",color:"#111"}}>
      <option value="">اختر...</option>
      {options.map(o=><option key={o.value||o} value={o.value||o}>{o.label||o}</option>)}
    </select>
  </div>
);

const Btn = ({children,onClick,variant="primary",style={},disabled=false}) => (
  <button onClick={onClick} disabled={disabled} style={{
    padding:"10px 16px",border:"none",borderRadius:8,cursor:disabled?"not-allowed":"pointer",
    fontSize:13,fontWeight:700,fontFamily:"inherit",opacity:disabled?0.5:1,
    background:variant==="primary"?"#1B2A4A":variant==="gold"?"#B8923C":variant==="danger"?"#FEF2F2":variant==="success"?"#F0FDF4":"#F9FAFB",
    color:variant==="primary"?"#B8923C":variant==="gold"?"#fff":variant==="danger"?"#EF4444":variant==="success"?"#166534":"#374151",
    border:variant!=="primary"&&variant!=="gold"?`1px solid ${variant==="danger"?"#FECACA":variant==="success"?"#BBF7D0":"#E5E7EB"}`:"none",
    ...style}}>{children}</button>
);

const Modal = ({title,children,onClose}) => (
  <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.6)",zIndex:200,display:"flex",alignItems:"flex-end"}} onClick={e=>e.target===e.currentTarget&&onClose()}>
    <div style={{background:"#fff",borderRadius:"20px 20px 0 0",width:"100%",maxHeight:"92vh",overflowY:"auto",padding:20}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
        <div style={{fontWeight:800,fontSize:16,color:"#1B2A4A"}}>{title}</div>
        <button onClick={onClose} style={{background:"none",border:"none",fontSize:22,cursor:"pointer",color:"#6B7280"}}>✕</button>
      </div>
      {children}
    </div>
  </div>
);

const Toast = ({msg}) => msg ? (
  <div style={{position:"fixed",bottom:90,left:16,right:16,background:"#1B2A4A",color:"#B8923C",borderRadius:12,padding:"12px 16px",fontSize:13,fontWeight:700,zIndex:300,textAlign:"center"}}>{msg}</div>
) : null;

const SectionTitle = ({children}) => (
  <div style={{fontSize:14,fontWeight:800,color:"#1B2A4A",marginBottom:10,marginTop:4,borderRight:"3px solid #B8923C",paddingRight:10}}>{children}</div>
);

