  const [role,setRole] = useState("مدير");
  const [name,setName] = useState("");
  return (
    <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#1B2A4A 0%,#0f1a2e 100%)",display:"flex",alignItems:"center",justifyContent:"center",padding:24}}>
      <div style={{background:"#fff",borderRadius:20,padding:36,width:"100%",maxWidth:380,textAlign:"center"}}>
        <div style={{fontSize:48,marginBottom:8}}>🏗️</div>
        <div style={{fontSize:22,fontWeight:800,color:"#1B2A4A"}}>Capital Homes</div>
        <div style={{fontSize:13,color:"#B8923C",fontWeight:700,marginBottom:32}}>كابيتال هومز للمقاولات</div>
        <Input label="الاسم" value={name} onChange={setName} placeholder="اسمك" required />
        <Select label="الدور الوظيفي" value={role} onChange={setRole} options={["مدير","مهندس","مشتريات"]} />
