// ============================================================
// DASHBOARD
// ============================================================
const Dashboard = ({role,requests,sites,notifs,attendance}) => {
  const active = sites.filter(s=>s.status==="جارٍ التنفيذ").length;
  const stopped = sites.filter(s=>s.status==="متوقف").length;
  const pending = requests.filter(r=>r.phase==="طلب").length;
  const avg = Math.round(sites.reduce((a,s)=>a+s.progress,0)/sites.length);
  const myNotifs = notifs.filter(n=>!n.read&&(role==="مدير"||n.role===role));
  const todayAtt = attendance.filter(a=>a.date===TODAY);
  const totalAbsent = todayAtt.reduce((s,a)=>s+(a.absentWorkers||0),0);

  return (
    <div>
      <div style={{fontSize:18,fontWeight:800,color:"#1B2A4A",marginBottom:4}}>لوحة التحكم</div>
      <div style={{fontSize:12,color:"#9CA3AF",marginBottom:16}}>DAMAC Hills 2 • {TODAY}</div>

      {myNotifs.length>0 && (
        <Card style={{background:"#FFF7ED",border:"1px solid #FED7AA",marginBottom:16}}>
          <div style={{fontWeight:700,color:"#92400E",marginBottom:8}}>🔔 إشعارات جديدة ({myNotifs.length})</div>
          {myNotifs.slice(0,3).map(n=>(
            <div key={n.id} style={{fontSize:12,color:"#78350F",padding:"4px 0",borderBottom:"1px solid #FED7AA"}}>{n.text}</div>
          ))}
        </Card>
      )}

      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:8}}>
        {[["مواقع نشطة",active,"#10B981"],["متوقفة",stopped,"#EF4444"],["طلبات معلقة",pending,"#F59E0B"]].map(([l,v,c])=>(
          <div key={l} style={{background:"#fff",borderRadius:12,padding:"12px 8px",boxShadow:"0 1px 4px rgba(0,0,0,0.08)",textAlign:"center"}}>
            <div style={{fontSize:26,fontWeight:800,color:c}}>{v}</div>
            <div style={{fontSize:10,color:"#6B7280",marginTop:2}}>{l}</div>
          </div>
        ))}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:16}}>
        {[["متوسط الإنجاز",`${avg}%`,"#B8923C"],["غياب اليوم",totalAbsent+" عامل","#EF4444"]].map(([l,v,c])=>(
          <div key={l} style={{background:"#fff",borderRadius:12,padding:"12px 8px",boxShadow:"0 1px 4px rgba(0,0,0,0.08)",textAlign:"center"}}>
            <div style={{fontSize:22,fontWeight:800,color:c}}>{v}</div>
            <div style={{fontSize:10,color:"#6B7280",marginTop:2}}>{l}</div>
          </div>
        ))}
      </div>

      <Card style={{background:"linear-gradient(135deg,#1B2A4A,#0f1a2e)",color:"#fff",marginBottom:16}}>
        <div style={{fontSize:13,color:"#B8923C",fontWeight:700,marginBottom:8}}>التقدم الإجمالي</div>
        <div style={{fontSize:32,fontWeight:800}}>{avg}%</div>
        <div style={{background:"rgba(255,255,255,0.15)",borderRadius:99,height:8,marginTop:10}}>
          <div style={{width:`${avg}%`,background:"#B8923C",borderRadius:99,height:8}}/>
        </div>
        <div style={{fontSize:11,color:"#94A3B8",marginTop:8}}>{sites.length} موقع — DAMAC Hills 2</div>
      </Card>

      <SectionTitle>آخر الطلبات</SectionTitle>
      {requests.slice(-4).reverse().map(r=>(
        <div key={r.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 0",borderBottom:"1px solid #F3F4F6"}}>
          <div>
            <div style={{fontSize:13,fontWeight:600}}>{r.material}</div>
            <div style={{fontSize:11,color:"#9CA3AF"}}>{r.site} • {r.date}</div>
          </div>
          <Badge label={r.phase} color={PHASE_COLOR[r.phase]||"#6B7280"}/>
        </div>
      ))}
    </div>
  );
};

// ============================================================
// ATTENDANCE SCREEN
// ============================================================
const AttendanceScreen = ({role,attendance,setAttendance,sites,showToast,addNotif}) => {
  const [modal,setModal] = useState(false);
  const [form,setForm] = useState({siteId:"",date:TODAY,engineer:"",engineerPresent:true,totalWorkers:"",absentWorkers:"",absentNames:"",notes:""});

  const todayRecs = attendance.filter(a=>a.date===TODAY);

  const save = () => {
    if(!form.siteId||!form.engineer) return;
    const site = sites.find(s=>s.id===form.siteId);
    const rec = {...form,id:`att-${Date.now()}`,siteName:site?.name||"",totalWorkers:+form.totalWorkers||0,absentWorkers:+form.absentWorkers||0};
    const upd = [...attendance,rec];
    setAttendance(upd);
    if(+form.absentWorkers>5){
      addNotif({id:`n${Date.now()}`,text:`⚠️ غياب ${form.absentWorkers} عمال في ${site?.name}`,role:"مدير",read:false,time:new Date().toLocaleString("ar")});
    }
    if(!form.engineerPresent){
      addNotif({id:`n${Date.now()+1}`,text:`⚠️ غياب المهندس ${form.engineer} — ${site?.name}`,role:"مدير",read:false,time:new Date().toLocaleString("ar")});
    }
    showToast("✓ تم تسجيل الحضور");
    setModal(false);
    setForm({siteId:"",date:TODAY,engineer:"",engineerPresent:true,totalWorkers:"",absentWorkers:"",absentNames:"",notes:""});
  };

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
        <div style={{fontSize:18,fontWeight:800,color:"#1B2A4A"}}>الحضور والغياب</div>
        <Btn onClick={()=>setModal(true)} variant="gold" style={{padding:"7px 14px",fontSize:12}}>+ تسجيل</Btn>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:16}}>
        <Card style={{margin:0,textAlign:"center"}}>
          <div style={{fontSize:24,fontWeight:800,color:"#10B981"}}>{todayRecs.reduce((s,a)=>s+(a.totalWorkers-a.absentWorkers),0)}</div>
          <div style={{fontSize:11,color:"#6B7280"}}>حاضرين اليوم</div>
        </Card>
        <Card style={{margin:0,textAlign:"center"}}>
          <div style={{fontSize:24,fontWeight:800,color:"#EF4444"}}>{todayRecs.reduce((s,a)=>s+a.absentWorkers,0)}</div>
          <div style={{fontSize:11,color:"#6B7280"}}>غائبين اليوم</div>
        </Card>
      </div>

      <SectionTitle>سجل اليوم — {TODAY}</SectionTitle>
      {todayRecs.length===0 && <Card><div style={{color:"#9CA3AF",textAlign:"center",padding:"20px 0"}}>لا توجد تسجيلات اليوم</div></Card>}
      {todayRecs.map(a=>(
        <Card key={a.id}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
            <div style={{fontWeight:700,fontSize:14}}>{a.siteName}</div>
            <Badge label={a.engineerPresent?"المهندس حاضر":"المهندس غائب"} color={a.engineerPresent?"#10B981":"#EF4444"}/>
          </div>
          <div style={{fontSize:13,color:"#374151",marginBottom:4}}>👷 {a.engineer}</div>
          <div style={{display:"flex",gap:16,fontSize:12,color:"#6B7280"}}>
            <span>إجمالي العمال: <b style={{color:"#1B2A4A"}}>{a.totalWorkers}</b></span>
            <span>غائبين: <b style={{color:"#EF4444"}}>{a.absentWorkers}</b></span>
            <span>حاضرين: <b style={{color:"#10B981"}}>{a.totalWorkers-a.absentWorkers}</b></span>
          </div>
          {a.absentNames && <div style={{fontSize:11,color:"#6B7280",marginTop:6,background:"#FEF2F2",padding:"6px 10px",borderRadius:6}}>غائبون: {a.absentNames}</div>}
          {a.notes && <div style={{fontSize:11,color:"#6B7280",marginTop:6,background:"#F9FAFB",padding:"6px 10px",borderRadius:6}}>ملاحظة: {a.notes}</div>}
        </Card>
      ))}

      {attendance.filter(a=>a.date!==TODAY).length>0 && (
        <>
          <SectionTitle>السجل السابق</SectionTitle>
          {attendance.filter(a=>a.date!==TODAY).slice(-10).reverse().map(a=>(
            <Card key={a.id} style={{borderRight:"3px solid #E5E7EB"}}>
              <div style={{display:"flex",justifyContent:"space-between"}}>
                <div style={{fontWeight:600,fontSize:13}}>{a.siteName}</div>
                <span style={{fontSize:11,color:"#9CA3AF"}}>{a.date}</span>
              </div>
              <div style={{fontSize:12,color:"#6B7280",marginTop:4}}>
                👷 {a.engineer} • حاضر: {a.totalWorkers-a.absentWorkers} • غائب: <span style={{color:"#EF4444"}}>{a.absentWorkers}</span>
              </div>
            </Card>
          ))}
        </>
      )}

      {modal && (
        <Modal title="تسجيل الحضور" onClose={()=>setModal(false)}>
          <Select label="الموقع" value={form.siteId} onChange={v=>setForm({...form,siteId:v})} options={sites.map(s=>({value:s.id,label:s.name}))} required/>
          <Input label="التاريخ" value={form.date} onChange={v=>setForm({...form,date:v})} type="date" required/>
          <Select label="المهندس المسؤول" value={form.engineer} onChange={v=>setForm({...form,engineer:v})} options={ENGINEERS} required/>
          <div style={{marginBottom:14}}>
            <div style={{fontSize:13,fontWeight:600,color:"#374151",marginBottom:8}}>حضور المهندس</div>
            <div style={{display:"flex",gap:8}}>
              <button onClick={()=>setForm({...form,engineerPresent:true})} style={{flex:1,padding:10,border:"none",borderRadius:8,cursor:"pointer",fontFamily:"inherit",fontSize:13,fontWeight:600,background:form.engineerPresent?"#10B981":"#E5E7EB",color:form.engineerPresent?"#fff":"#374151"}}>✓ حاضر</button>
              <button onClick={()=>setForm({...form,engineerPresent:false})} style={{flex:1,padding:10,border:"none",borderRadius:8,cursor:"pointer",fontFamily:"inherit",fontSize:13,fontWeight:600,background:!form.engineerPresent?"#EF4444":"#E5E7EB",color:!form.engineerPresent?"#fff":"#374151"}}>✗ غائب</button>
            </div>
          </div>
          <div style={{display:"flex",gap:8}}>
            <div style={{flex:1}}><Input label="إجمالي العمال" value={form.totalWorkers} onChange={v=>setForm({...form,totalWorkers:v})} type="number" placeholder="0"/></div>
            <div style={{flex:1}}><Input label="الغائبون" value={form.absentWorkers} onChange={v=>setForm({...form,absentWorkers:v})} type="number" placeholder="0"/></div>
          </div>
          <Input label="أسماء الغائبين (اختياري)" value={form.absentNames} onChange={v=>setForm({...form,absentNames:v})} placeholder="مثال: علي محمد، أحمد سيد"/>
          <Input label="ملاحظات" value={form.notes} onChange={v=>setForm({...form,notes:v})} placeholder="أي ملاحظات إضافية" rows={2}/>
          <div style={{display:"flex",gap:8}}>
            <Btn onClick={save} style={{flex:1}} disabled={!form.siteId||!form.engineer}>حفظ</Btn>
            <Btn onClick={()=>setModal(false)} variant="secondary">إلغاء</Btn>
          </div>
        </Modal>
      )}
    </div>
  );
};

// ============================================================
// DAILY REPORT SCREEN
// ============================================================
const DailyReports = ({role,reports,setReports,sites,showToast,addNotif,userName}) => {
  const [modal,setModal] = useState(false);
  const [commentModal,setCommentModal] = useState(null);
  const [comment,setComment] = useState("");
  const [filterSite,setFilterSite] = useState("");
  const fileRef = useRef();

  const [form,setForm] = useState({
    siteId:"",date:TODAY,engineer:"",
    works:"",subContractors:"",issues:"",
    photos:[],notes:""
  });

  const handlePhotos = (e) => {
    const files = Array.from(e.target.files);
    files.forEach(f=>{
      const reader = new FileReader();
      reader.onload = ev => {
        setForm(prev=>({...prev,photos:[...prev.photos,{id:Date.now()+Math.random(),data:ev.target.result,name:f.name,comments:[]}]}));
      };
      reader.readAsDataURL(f);
    });
  };

  const saveReport = () => {
    if(!form.siteId||!form.engineer||!form.works.trim()) return;
    const site = sites.find(s=>s.id===form.siteId);
    const rep = {...form,id:`rep-${Date.now()}`,siteName:site?.name||"",createdBy:userName,createdAt:new Date().toISOString()};
    const upd = [...reports,rep];
    setReports(upd);
    addNotif({id:`n${Date.now()}`,text:`📋 تقرير يومي جديد من ${form.engineer} — ${site?.name}`,role:"مدير",read:false,time:new Date().toLocaleString("ar")});
    showToast("✓ تم رفع التقرير");
    setModal(false);
    setForm({siteId:"",date:TODAY,engineer:"",works:"",subContractors:"",issues:"",photos:[],notes:""});
  };

  const addComment = (repId,photoId) => {
    if(!comment.trim()) return;
    const upd = reports.map(r=>r.id===repId?{...r,photos:r.photos.map(p=>p.id===photoId?{...p,comments:[...p.comments,{text:comment,by:userName,time:new Date().toLocaleString("ar")}]}:p)}:r);
    setReports(upd);
    setComment("");
    setCommentModal(null);
    showToast("✓ تم إضافة التعليق");
  };

  const filtered = filterSite ? reports.filter(r=>r.siteId===filterSite) : reports;

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
        <div style={{fontSize:18,fontWeight:800,color:"#1B2A4A"}}>التقارير اليومية</div>
        {role==="مهندس" && <Btn onClick={()=>setModal(true)} variant="gold" style={{padding:"7px 14px",fontSize:12}}>+ تقرير جديد</Btn>}
      </div>

      <select value={filterSite} onChange={e=>setFilterSite(e.target.value)}
        style={{width:"100%",padding:"10px 12px",border:"1px solid #D1D5DB",borderRadius:10,fontSize:13,direction:"rtl",fontFamily:"inherit",background:"#fff",marginBottom:14,color:"#111"}}>
        <option value="">كل المواقع</option>
        {sites.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
      </select>

      {filtered.length===0 && <Card><div style={{color:"#9CA3AF",textAlign:"center",padding:"20px 0"}}>لا توجد تقارير</div></Card>}

      {filtered.slice().reverse().map(rep=>(
        <Card key={rep.id} style={{borderRight:"3px solid #B8923C"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
            <div>
              <div style={{fontWeight:800,fontSize:14,color:"#1B2A4A"}}>{rep.siteName}</div>
              <div style={{fontSize:12,color:"#6B7280"}}>👷 {rep.engineer} • {rep.date}</div>
              <div style={{fontSize:11,color:"#9CA3AF"}}>رُفع بواسطة: {rep.createdBy}</div>
            </div>
            <Badge label={rep.date===TODAY?"اليوم":"سابق"} color={rep.date===TODAY?"#10B981":"#6B7280"}/>
          </div>

          <div style={{background:"#F9FAFB",borderRadius:10,padding:12,marginBottom:10}}>
            <div style={{fontSize:11,fontWeight:700,color:"#B8923C",marginBottom:4}}>🔨 الأعمال المنفذة</div>
            <div style={{fontSize:13,color:"#374151",whiteSpace:"pre-wrap"}}>{rep.works}</div>
          </div>

          {rep.subContractors && (
            <div style={{background:"#EFF6FF",borderRadius:10,padding:12,marginBottom:10}}>
              <div style={{fontSize:11,fontWeight:700,color:"#3B82F6",marginBottom:4}}>👷 مقاولو الباطن</div>
              <div style={{fontSize:13,color:"#374151",whiteSpace:"pre-wrap"}}>{rep.subContractors}</div>
            </div>
          )}

          {rep.issues && (
            <div style={{background:"#FEF2F2",borderRadius:10,padding:12,marginBottom:10}}>
              <div style={{fontSize:11,fontWeight:700,color:"#EF4444",marginBottom:4}}>⚠️ مشاكل / ملاحظات</div>
              <div style={{fontSize:13,color:"#374151",whiteSpace:"pre-wrap"}}>{rep.issues}</div>
            </div>
          )}

          {rep.photos?.length>0 && (
