const FormalRequests = ({role,formalReqs,setFormalReqs,sites,showToast,addNotif,userName}) => {
  const [modal,setModal] = useState(false);
  const [form,setForm] = useState({siteId:"",date:TODAY,type:"طلب بلدية",subject:"",details:"",status:"جديد"});

  const save = () => {
    if(!form.siteId||!form.subject.trim()) return;
    const site = sites.find(s=>s.id===form.siteId);
    const req = {...form,id:`fr-${Date.now()}`,siteName:site?.name||"",createdBy:userName,createdAt:new Date().toISOString()};
    const upd=[...formalReqs,req];
    setFormalReqs(upd);
    addNotif({id:`n${Date.now()}`,text:`📋 ${form.type} جديد: ${form.subject} — ${site?.name}`,role:"مدير",read:false,time:new Date().toLocaleString("ar")});
    showToast("✓ تم إرسال الطلب");
    setModal(false);
    setForm({siteId:"",date:TODAY,type:"طلب بلدية",subject:"",details:"",status:"جديد"});
  };

  const statusColor = {"جديد":"#3B82F6","قيد المعالجة":"#F59E0B","مكتمل":"#10B981","مرفوض":"#EF4444"};

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
        <div style={{fontSize:18,fontWeight:800,color:"#1B2A4A"}}>الطلبات الرسمية</div>
        {(role==="مهندس"||role==="مدير") && <Btn onClick={()=>setModal(true)} variant="gold" style={{padding:"7px 14px",fontSize:12}}>+ طلب جديد</Btn>}
      </div>

      {formalReqs.length===0 && <Card><div style={{color:"#9CA3AF",textAlign:"center",padding:"20px 0"}}>لا توجد طلبات رسمية</div></Card>}

      {formalReqs.slice().reverse().map(r=>(
        <Card key={r.id} style={{borderRight:`3px solid ${statusColor[r.status]||"#6B7280"}`}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
            <div>
              <Badge label={r.type} color="#8B5CF6"/>
              <div style={{fontWeight:700,fontSize:14,marginTop:6}}>{r.subject}</div>
              <div style={{fontSize:12,color:"#6B7280"}}>{r.siteName} • {r.date}</div>
              <div style={{fontSize:11,color:"#9CA3AF"}}>{r.createdBy}</div>
            </div>
            <Badge label={r.status} color={statusColor[r.status]||"#6B7280"}/>
          </div>
          {r.details && <div style={{fontSize:12,color:"#374151",background:"#F9FAFB",padding:"8px 12px",borderRadius:8,marginTop:8}}>{r.details}</div>}
          {role==="مدير" && r.status==="جديد" && (
            <div style={{display:"flex",gap:8,marginTop:10}}>
              <Btn onClick={()=>{const u=formalReqs.map(x=>x.id===r.id?{...x,status:"قيد المعالجة"}:x);setFormalReqs(u);showToast("تم تحديث الحالة");}} variant="success" style={{flex:1,fontSize:12}}>قيد المعالجة</Btn>
              <Btn onClick={()=>{const u=formalReqs.map(x=>x.id===r.id?{...x,status:"مكتمل"}:x);setFormalReqs(u);showToast("تم الإنجاز");}} style={{flex:1,fontSize:12}}>✓ مكتمل</Btn>
            </div>
          )}
