      ))}

      {modal && (
        <Modal title="طلب رسمي جديد" onClose={()=>setModal(false)}>
          <Select label="الموقع" value={form.siteId} onChange={v=>setForm({...form,siteId:v})} options={sites.map(s=>({value:s.id,label:s.name}))} required/>
          <Select label="نوع الطلب" value={form.type} onChange={v=>setForm({...form,type:v})} options={["طلب بلدية","طلب للاستشاري","طلب لجهة حكومية","مراسلة رسمية","أخرى"]} required/>
