// ============================================================
// PROCUREMENT
// ============================================================
const Procurement = ({role,requests,setRequests,addNotif,showToast}) => {
  const [filter,setFilter] = useState("الكل");
  const [rejectModal,setRejectModal] = useState(null);
  const [rejectReason,setRejectReason] = useState("");
  const filtered = filter==="الكل"?requests:requests.filter(r=>r.phase===filter);

  const advance = r => {
    const next=PHASE_NEXT[r.phase];
    if(!next)return;
    const upd=requests.map(x=>x.id===r.id?{...x,phase:next}:x);
    setRequests(upd);
    addNotif({id:`n${Date.now()}`,text:`✅ "${r.material}" تم تحريكه إلى: ${next}`,role:"مهندس",read:false,time:new Date().toLocaleString("ar")});
    showToast(`✓ تم: ${next}`);
  };

  const reject = r => {
    const upd=requests.map(x=>x.id===r.id?{...x,phase:"مرفوض",rejectedReason:rejectReason}:x);
    setRequests(upd);
    addNotif({id:`n${Date.now()}`,text:`❌ رُفض طلب "${r.material}" — ${rejectReason}`,role:"مهندس",read:false,time:new Date().toLocaleString("ar")});
    setRejectModal(null);setRejectReason("");
    showToast("تم الرفض");
  };

  return (
    <div>
      <div style={{fontSize:18,fontWeight:800,color:"#1B2A4A",marginBottom:4}}>المشتريات</div>
      <div style={{fontSize:12,color:"#9CA3AF",marginBottom:12}}>{requests.filter(r=>r.phase==="طلب").length} طلب جديد • {requests.length} إجمالي</div>
      <div style={{display:"flex",gap:6,overflowX:"auto",paddingBottom:8,marginBottom:14}}>
        {["الكل",...PHASES,"مرفوض"].map(f=>(
          <button key={f} onClick={()=>setFilter(f)} style={{padding:"6px 14px",border:"none",borderRadius:20,cursor:"pointer",whiteSpace:"nowrap",fontSize:11,fontWeight:600,fontFamily:"inherit",background:filter===f?"#1B2A4A":"#E5E7EB",color:filter===f?"#B8923C":"#374151"}}>{f}</button>
        ))}
      </div>
      {filtered.length===0&&<Card><div style={{color:"#9CA3AF",textAlign:"center",padding:"20px 0"}}>لا توجد طلبات</div></Card>}
      {filtered.map(r=>(
        <Card key={r.id}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
            <div>
              <div style={{fontSize:10,color:"#9CA3AF"}}>{r.id}</div>
              <div style={{fontWeight:700,fontSize:14}}>{r.material}</div>
              <div style={{fontSize:12,color:"#6B7280"}}>{r.site} • {r.qty} {r.unit}</div>
              <div style={{fontSize:11,color:"#9CA3AF"}}>{r.requestedBy} • {r.date}</div>
            </div>
            <Badge label={r.phase} color={r.phase==="مرفوض"?"#EF4444":PHASE_COLOR[r.phase]||"#6B7280"}/>
          </div>
          {r.phase!=="مرفوض"&&<PhaseBar current={r.phase}/>}
          {r.rejectedReason&&<div style={{marginTop:8,fontSize:11,color:"#EF4444",background:"#FEF2F2",padding:"6px 10px",borderRadius:6}}>سبب الرفض: {r.rejectedReason}</div>}
          {r.notes&&<div style={{marginTop:6,fontSize:11,color:"#6B7280",background:"#F9FAFB",padding:"6px 10px",borderRadius:6}}>ملاحظة: {r.notes}</div>}
          {(role==="مدير"||role==="مشتريات")&&r.phase!=="صرف"&&r.phase!=="مرفوض"&&(
            <div style={{display:"flex",gap:8,marginTop:12}}>
              <Btn onClick={()=>advance(r)} style={{flex:1}}>✓ {PHASE_NEXT[r.phase]?`→ ${PHASE_NEXT[r.phase]}`:"مكتمل"}</Btn>
              <Btn onClick={()=>setRejectModal(r)} variant="danger">رفض</Btn>
            </div>
          )}
        </Card>
      ))}
      {rejectModal&&(
        <Modal title="سبب الرفض" onClose={()=>setRejectModal(null)}>
          <div style={{fontSize:13,color:"#6B7280",marginBottom:12}}>طلب: {rejectModal.material}</div>
          <Input label="سبب الرفض" value={rejectReason} onChange={setRejectReason} placeholder="اكتب السبب..." required/>
          <div style={{display:"flex",gap:8}}>
            <Btn onClick={()=>reject(rejectModal)} variant="danger" style={{flex:1}} disabled={!rejectReason.trim()}>تأكيد الرفض</Btn>
            <Btn onClick={()=>setRejectModal(null)} variant="secondary">إلغاء</Btn>
          </div>
        </Modal>
      )}
    </div>
  );
};

