    <div>
      <button onClick={onBack} style={{background:"none",border:"none",color:"#B8923C",fontWeight:700,cursor:"pointer",fontSize:14,marginBottom:10,padding:0,fontFamily:"inherit"}}>← رجوع</button>
      <div style={{background:"#1B2A4A",borderRadius:16,padding:20,marginBottom:16,color:"#fff"}}>
        <div style={{fontSize:20,fontWeight:800}}>{site.name}</div>
        <div style={{fontSize:13,color:"#B8923C",marginTop:4}}>قطعة {site.plot}</div>
        <div style={{fontSize:12,marginTop:6,color:"#94A3B8"}}>👷 {site.engineer}</div>
        <div style={{marginTop:14}}>
          <div style={{display:"flex",justifyContent:"space-between",fontSize:11,color:"#94A3B8",marginBottom:4}}><span>التقدم</span><span>{site.progress}%</span></div>
          <div style={{background:"#0f1a2e",borderRadius:99,height:8}}>
            <div style={{width:`${site.progress}%`,background:"#B8923C",borderRadius:99,height:8}}/>
          </div>
        </div>
        {role==="مدير"&&<button onClick={()=>setModal("progress")} style={{marginTop:10,background:"rgba(184,146,60,0.2)",border:"1px solid #B8923C",color:"#B8923C",borderRadius:8,padding:"5px 12px",fontSize:11,cursor:"pointer",fontFamily:"inherit"}}>تحديث التقدم</button>}
      </div>

      <div style={{display:"flex",gap:6,marginBottom:16}}>
        {[["overview","نظرة عامة"],["reqs","المواد"],["docs","الوثائق"]].map(([k,l])=>(
          <button key={k} onClick={()=>setTab(k)} style={{flex:1,padding:"9px 4px",border:"none",borderRadius:8,cursor:"pointer",fontSize:12,fontFamily:"inherit",background:tab===k?"#1B2A4A":"#E5E7EB",color:tab===k?"#B8923C":"#374151",fontWeight:tab===k?700:400}}>{l}</button>
        ))}
      </div>

      {tab==="overview"&&(
        <Card>
          <SectionTitle>معلومات الموقع</SectionTitle>
          {[["الحالة",<Badge label={site.status} color={STATUS_COLOR[site.status]}/>],["المهندس",site.engineer],["القطعة",site.plot],["الإنجاز",`${site.progress}%`],["طلبات المواد",siteReqs.length],["الوثائق",siteDocs.length]].map(([k,v])=>(
            <div key={k} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"8px 0",borderBottom:"1px solid #F3F4F6",fontSize:13}}>
              <span style={{color:"#6B7280"}}>{k}</span><span style={{fontWeight:600}}>{v}</span>
            </div>
          ))}
        </Card>
      )}

      {tab==="reqs"&&(
        <div>
          {role==="مهندس"&&<Btn onClick={()=>setModal("addReq")} variant="gold" style={{width:"100%",marginBottom:12}}>+ طلب مواد جديد</Btn>}
          {siteReqs.length===0?<Card><div style={{color:"#9CA3AF",textAlign:"center",padding:"20px 0"}}>لا توجد طلبات</div></Card>
          :siteReqs.map(r=>(
            <Card key={r.id}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
                <div><div style={{fontWeight:700,fontSize:13}}>{r.material}</div><div style={{fontSize:11,color:"#9CA3AF"}}>{r.qty} {r.unit} • {r.date}</div></div>
                <Badge label={r.phase} color={PHASE_COLOR[r.phase]||"#6B7280"}/>
              </div>
              <PhaseBar current={r.phase}/>
              {r.notes&&<div style={{marginTop:8,fontSize:11,color:"#6B7280",background:"#F9FAFB",padding:"6px 10px",borderRadius:6}}>ملاحظة: {r.notes}</div>}
            </Card>
          ))}
        </div>
      )}

      {tab==="docs"&&(
        <div>
          {(role==="مهندس"||role==="مدير")&&<Btn onClick={()=>setModal("addDoc")} variant="gold" style={{width:"100%",marginBottom:12}}>+ إضافة وثيقة</Btn>}
          {siteDocs.length===0?<Card><div style={{color:"#9CA3AF",textAlign:"center",padding:"20px 0"}}>لا توجد وثائق</div></Card>
          :siteDocs.map(d=>(
            <Card key={d.id}>
              <div style={{display:"flex",gap:12,alignItems:"center"}}>
                <div style={{width:44,height:44,borderRadius:10,background:"#EFF6FF",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0}}>{TYPE_ICON[d.type]||"📄"}</div>
                <div><div style={{fontWeight:700,fontSize:13}}>{d.title}</div><div style={{fontSize:11,color:"#9CA3AF"}}>{d.type} • {d.date} • {d.by}</div></div>
              </div>
            </Card>
          ))}
        </div>
      )}

      {modal==="progress"&&(
        <Modal title="تحديث نسبة التقدم" onClose={()=>setModal(null)}>
          <div style={{fontSize:13,marginBottom:8}}>النسبة الحالية: {site.progress}%</div>
          <input type="range" min="0" max="100" value={newProgress} onChange={e=>setNewProgress(+e.target.value)} style={{width:"100%",marginBottom:8}}/>
          <div style={{textAlign:"center",fontSize:28,fontWeight:800,color:"#1B2A4A",marginBottom:16}}>{newProgress}%</div>
          <Btn onClick={()=>{const upd=sites.map(s=>s.id===site.id?{...s,progress:newProgress}:s);setSites(upd);setModal(null);showToast("✓ تم تحديث التقدم");}} style={{width:"100%"}}>حفظ</Btn>
        </Modal>
      )}
      {modal==="addReq"&&<AddRequestModal site={site} userName={userName} onClose={()=>setModal(null)} onSave={saveReq}/>}
      {modal==="addDoc"&&(
        <Modal title="إضافة وثيقة" onClose={()=>setModal(null)}>
          {(()=>{
            const [t,setT]=useState("");const [ty,setTy]=useState("رسالة");const [n,setN]=useState("");
            return(<>
              <Input label="عنوان الوثيقة" value={t} onChange={setT} placeholder="عنوان الوثيقة" required/>
              <Select label="النوع" value={ty} onChange={setTy} options={["رسالة","تقرير تقدم","أمر تغيير","رسم هندسي","أخرى"]}/>
              <Input label="ملاحظات" value={n} onChange={setN} placeholder="ملاحظات..." rows={2}/>
              <div style={{display:"flex",gap:8}}>
                <Btn onClick={()=>{if(!t.trim())return;saveDoc({id:`doc-${Date.now()}`,siteId:site.id,site:site.name,title:t.trim(),type:ty,by:userName,date:TODAY,notes:n});setModal(null);}} style={{flex:1}} disabled={!t.trim()}>حفظ</Btn>
                <Btn onClick={()=>setModal(null)} variant="secondary">إلغاء</Btn>
              </div>
            </>);
          })()}
        </Modal>
      )}
    </div>
  );
};

// ============================================================
// MAIN APP
// ============================================================
export default function App() {
  const [user,setUser] = useState(null);
  const [screen,setScreen] = useState("dashboard");
  const [selectedSite,setSelectedSite] = useState(null);
  const [addSiteModal,setAddSiteModal] = useState(false);

  const [sites,setSitesRaw] = useState(()=>load("ch_sites",INIT_SITES));
  const [requests,setRequestsRaw] = useState(()=>load("ch_requests",INIT_REQUESTS));
  const [docs,setDocsRaw] = useState(()=>load("ch_docs",[]));
  const [notifs,setNotifsRaw] = useState(()=>load("ch_notifs",[]));
  const [attendance,setAttendanceRaw] = useState(()=>load("ch_attendance",[]));
  const [reports,setReportsRaw] = useState(()=>load("ch_reports",[]));
  const [formalReqs,setFormalReqsRaw] = useState(()=>load("ch_formal",[]) );

  const setSites = v=>{setSitesRaw(v);save("ch_sites",v);};
  const setRequests = v=>{setRequestsRaw(v);save("ch_requests",v);};
  const setDocs = v=>{setDocsRaw(v);save("ch_docs",v);};
  const setNotifs = v=>{setNotifsRaw(v);save("ch_notifs",v);};
  const setAttendance = v=>{setAttendanceRaw(v);save("ch_attendance",v);};
  const setReports = v=>{setReportsRaw(v);save("ch_reports",v);};
  const setFormalReqs = v=>{setFormalReqsRaw(v);save("ch_formal",v);};

  const [toast,setToast] = useState("");
  const showToast = msg=>{setToast(msg);setTimeout(()=>setToast(""),2500);};
  const addNotif = n=>{const upd=[n,...notifs];setNotifs(upd);};

  const unread = notifs.filter(n=>!n.read&&(user?.role==="مدير"||n.role===user?.role)).length;

  if(!user) return <Login onLogin={(role,name)=>setUser({role,name})}/>;

  const navItems = [
    {key:"dashboard",label:"الرئيسية",icon:"🏠"},
    {key:"sites",label:"المواقع",icon:"🏗️"},
    {key:"reports",label:"التقارير",icon:"📋"},
    {key:"more",label:"المزيد",icon:"⋯"},
  ];

  const moreItems = [
    {key:"attendance",label:"الحضور والغياب",icon:"👷"},
    {key:"procurement",label:"المشتريات",icon:"📦"},
    {key:"formal",label:"الطلبات الرسمية",icon:"📝"},
    {key:"notifs",label:`الإشعارات${unread>0?` (${unread})`:""}`,icon:"🔔"},
  ];

  return (
    <div style={{fontFamily:"'Cairo','Segoe UI',sans-serif",direction:"rtl",background:"#F3F4F6",minHeight:"100vh"}}>
      <div style={{background:"#1B2A4A",padding:"12px 16px",display:"flex",justifyContent:"space-between",alignItems:"center",position:"sticky",top:0,zIndex:100}}>
        <div style={{color:"#B8923C",fontWeight:800,fontSize:16}}>🏗️ Capital Homes</div>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <span style={{fontSize:12,color:"#94A3B8"}}>{user.name}</span>
          <Badge label={user.role} color={ROLE_COLOR[user.role]||"#6B7280"}/>
          {unread>0&&<span style={{background:"#EF4444",color:"#fff",borderRadius:99,fontSize:10,fontWeight:800,padding:"2px 6px"}}>{unread}</span>}
          <button onClick={()=>{setUser(null);setScreen("dashboard");setSelectedSite(null);}} style={{background:"none",border:"1px solid #374151",color:"#9CA3AF",borderRadius:6,padding:"4px 8px",cursor:"pointer",fontSize:11,fontFamily:"inherit"}}>خروج</button>
        </div>
      </div>

      <div style={{padding:"16px 16px 80px"}}>
        {screen==="dashboard"&&<Dashboard role={user.role} requests={requests} sites={sites} notifs={notifs} attendance={attendance}/>}
        {screen==="sites"&&!selectedSite&&<SitesList sites={sites} role={user.role} onSelect={s=>setSelectedSite(s)} onAdd={()=>setAddSiteModal(true)}/>}
        {screen==="sites"&&selectedSite&&<SiteDetail site={selectedSite} role={user.role} userName={user.name} requests={requests} docs={docs} setRequests={setRequests} setDocs={setDocs} addNotif={addNotif} onBack={()=>setSelectedSite(null)} showToast={showToast} sites={sites} setSites={setSites}/>}
        {screen==="reports"&&<DailyReports role={user.role} reports={reports} setReports={setReports} sites={sites} showToast={showToast} addNotif={addNotif} userName={user.name}/>}
        {screen==="attendance"&&<AttendanceScreen role={user.role} attendance={attendance} setAttendance={setAttendance} sites={sites} showToast={showToast} addNotif={addNotif}/>}
        {screen==="procurement"&&<Procurement role={user.role} requests={requests} setRequests={setRequests} addNotif={addNotif} showToast={showToast}/>}
        {screen==="formal"&&<FormalRequests role={user.role} formalReqs={formalReqs} setFormalReqs={setFormalReqs} sites={sites} showToast={showToast} addNotif={addNotif} userName={user.name}/>}
        {screen==="notifs"&&<Notifications notifs={notifs} setNotifs={setNotifs} role={user.role}/>}
        {screen==="more"&&(
          <div>
            <div style={{fontSize:18,fontWeight:800,color:"#1B2A4A",marginBottom:16}}>المزيد</div>
            {moreItems.map(item=>(
              <div key={item.key} onClick={()=>setScreen(item.key)} style={{background:"#fff",borderRadius:12,padding:"16px",marginBottom:10,boxShadow:"0 1px 4px rgba(0,0,0,0.08)",cursor:"pointer",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <div style={{display:"flex",alignItems:"center",gap:12}}>
                  <span style={{fontSize:24}}>{item.icon}</span>
                  <span style={{fontWeight:700,fontSize:15,color:"#1B2A4A"}}>{item.label}</span>
                </div>
                <span style={{color:"#9CA3AF",fontSize:18}}>←</span>
              </div>
            ))}
            <div style={{marginTop:24,padding:16,background:"#fff",borderRadius:12,textAlign:"center"}}>
              <div style={{fontSize:11,color:"#9CA3AF"}}>Capital Homes Contracting</div>
              <div style={{fontSize:11,color:"#9CA3AF"}}>DAMAC Hills 2 — Dubai, UAE</div>
              <div style={{fontSize:11,color:"#B8923C",marginTop:4,fontWeight:600}}>v2.0</div>
            </div>
          </div>
        )}
      </div>

      {addSiteModal&&<AddSiteModal onClose={()=>setAddSiteModal(false)} onSave={s=>{const upd=[...sites,s];setSites(upd);showToast("✓ تم إضافة الموقع");setAddSiteModal(false);}}/>}
      <Toast msg={toast}/>

      <div style={{position:"fixed",bottom:0,left:0,right:0,background:"#fff",borderTop:"1px solid #E5E7EB",display:"flex",zIndex:100}}>
        {navItems.map(item=>(
          <button key={item.key} onClick={()=>{setScreen(item.key);setSelectedSite(null);}} style={{flex:1,padding:"10px 4px 8px",border:"none",background:"none",cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",gap:2,fontFamily:"inherit",position:"relative"}}>
            <span style={{fontSize:20}}>{item.icon}</span>
            <span style={{fontSize:10,fontWeight:600,color:screen===item.key?"#1B2A4A":"#9CA3AF"}}>{item.label}</span>
            {screen===item.key&&<div style={{width:20,height:3,background:"#B8923C",borderRadius:99}}/>}
          </button>
        ))}
      </div>
    </div>
  );
}
